window.__QUIZ_DATA__=[{"id":"objective>Physics>2007>1","subject":"Physics","year":"2007","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"Which of the following observations is not an effect of surface tension?","images":[],"options":{"A":"Droplets of water dripping slowly from a tap","B":"Mercury spilled on a clean glass plate forms small spherical droplets","C":"An insect walking across the surface of a pond","D":"Water flowing out more easily than engine oil from container"},"answer":"D","explanation":"The observation that is not an effect of surface tension is:    D) Water flowing out more easily than engine oil from a container.    Surface tension is a property of liquids that results from the cohesive forces between molecules at the liquid's surface. It tends to minimize the surface area and causes liquids to form into rounded shapes (like droplets) and resist spreading. This property explains observations A, B, and C.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>2","subject":"Physics","year":"2007","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : DERIVED QUANTITIES AND UNITS","question":"Which of the physical quantities is correctly paired with its corresponding S.I. unit?","images":[],"options":{"A":"Density [kg m3]","B":"Power [J s-1]","C":"Specific latent heat [J kg-1 k-1]","D":"Pressure [N m-1]"},"answer":"B","explanation":"Power=EnergyTime  \u2234TheS.IunitofPower=TheS.I unit of Energy The S.I unit of Time  The S.I unit of Power = J/S = JS-1","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>3","subject":"Physics","year":"2007","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A liquid of volume 2.00 m3 and density 1.00 \u00d7 103 kg m-3 is mixed with 3.00 m3 of another liquid of density 8.00 \u00d7 103 kg m3. Calculate the density of the mixture.  [Assume there is no chemical reaction]","images":[],"options":{"A":"5.20 \u00d7 102 kg m-3","B":"8.80 \u00d7 102 kg m-3","C":"1.13 \u00d7 102 kg m-3","D":"5.20 \u00d7 103 kg m-3"},"answer":"D","explanation":"Given: V1 = 2.00m3; V2 = 3.00m3  m1 = p1v1 = 2.00 \u00d7 1.0 \u00d7 103 = 2 \u00d7 103kg  m2 = p2v2 = 8.00 \u00d7 103 \u00d7 3.00 = 24 \u00d7 103  Thedensityofthemixture=m1 + m2v1 + v2=(24 + 2) \u00d7 1035=26 \u00d7 1035  = 5.2 \u00d7 103kgm-3","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>4","subject":"Physics","year":"2007","type":"Objective","topic":"MOTION : SOLID FRICTION","question":"Which of the following statements about solid friction are correct? It  I. is a force  II. occurs between the surfaces of two bodies in contact  III. depends on the area of contact","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"- Solid friction is a force.  - Solid friction occurs between the two surfaces in contact.  - Solid friction does not depend on the area of contact.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>5","subject":"Physics","year":"2007","type":"Objective","topic":"MOTION : CAUSE OF MOTION","question":"A man of mass m, experiences a viscous drag, F and an upthrust, U as he descends towards the ground at a steady velocity, using a parachute. If the acceleration of free fall is g, which of the following expression is correct?","images":[],"options":{"A":"FU = mg","B":"U + F - mg = 0","C":"U - F = mg","D":"F - U - mg = 0"},"answer":"B","explanation":"Upthrust and viscous drag act upwards while the weight of the man acts downwards.  Therefore, total upward force = Total downward Force  \u2234 U + F = W (W = mg)  U + F = mg  U + F - mg = 0","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>6","subject":"Physics","year":"2007","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"A body moving at a constant speed accelerates when it is in","images":[],"options":{"A":"rectilinear motion","B":"translational motion","C":"circular motion","D":"vibrational motion"},"answer":"C","explanation":"A body moving at a constant speed can accelerate if it is in circular motion. This is because acceleration is a change in velocity, and velocity is a vector quantity, meaning it has both magnitude (speed) and direction. In circular motion, the direction of the velocity is constantly changing, even if the speed is constant, so there is acceleration.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>7","subject":"Physics","year":"2007","type":"Objective","topic":"MOTION : CONCEPT OF VELOCITY","question":"An object of mass 2kg moves with a uniform speed of 10 ms-1 for 5s along a straight path. Determine the magnitude of its acceleration.","images":[],"options":{"A":"0 ms-2","B":"1 ms-2","C":"3 ms-2","D":"4 ms-2"},"answer":"A","explanation":"Given:  The mass, m of the object = 2kg  The uniform speed, v = 10ms-1  The time, t = 5s  a = 0 (since the speed is uniform).","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>8","subject":"Physics","year":"2007","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"The term rectilinear acceleration means the rate of increase of","images":[],"options":{"A":"velocity along a circular path in a unit time","B":"distance along a rectangular path in a unit time","C":"displacement along a straight-line path in a unit time","D":"velocity along a straight path in a unit time"},"answer":"D","explanation":"Rectilinear acceleration means the rate of increase of velocity along a straight-line path in a unit time.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>9","subject":"Physics","year":"2007","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A vehicle moving with a uniform speed is gradually brought to rest. Which of the following sketches describe the motion of the vehicle?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"The sketch that best describe the motion of the vehicle is:","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>10","subject":"Physics","year":"2007","type":"Objective","topic":"RECTILINEAR ACCELERATION : EQUATIONS OF MOTION WITH CONSTANT ACCELERATION","question":"A body moving with an initial velocity u accelerates until it attains a velocity of v within a time t. The distance, s covered by the body is given by the expression","images":[],"options":{"A":"s=(v - 2u2)t","B":"s=(v + 2u2)t","C":"s=(v + u2)t","D":"s=(2v + u2)t"},"answer":"C","explanation":"This is one of the equations of motion.  Distance = Average velocity \u00d7 Time  s=(v + u2)t","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>11","subject":"Physics","year":"2007","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A body accelerates uniformly from rest at 2ms-2. Calculate the magnitude of its velocity after travelling 9m.","images":[],"options":{"A":"4.5 ms-1","B":"6.0 ms-1","C":"18.0 ms-1","D":"36.0 ms-1"},"answer":"B","explanation":"Initially velocity, u = 0 (since it's from rest)  Final velocity, v = V  Distance travelled, s = 9m  Acceleration, a = 2 ms-2  Recall: v2 = u2 + 2as  v2 = 02 + 2(2)(9)  v2 = 36  v = &radic;36&nbsp;   = 6ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>12","subject":"Physics","year":"2007","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"The diagram above illustrates three forces acting on an object at point O. If the object is in equilibrium, determine the magnitude of the force P.","images":["data:image/png;base64,"],"options":{"A":"10.5 N","B":"11.0 N","C":"17.3 N","D":"20.0 N"},"answer":"D","explanation":"\u2234 10 = P sin 30\u00b0  \u2234 P = 20.0N    The magnitude of the force P is 20N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>13","subject":"Physics","year":"2007","type":"Objective","topic":"WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY","question":"A swinging pendulum between the rest position and its maximum displacement possesses","images":[],"options":{"A":"kinetic energy only","B":"potential energy only","C":"gravitational energy only","D":"both kinetic and potential energy"},"answer":"D","explanation":"The question is about the concept of energy in simple harmonic motion. A swinging pendulum possesses both kinetic and potential energy. At the maximum displacement, the pendulum has maximum potential energy and minimum kinetic energy. At the rest position, the pendulum has maximum kinetic energy and minimum potential energy. Therefore, the correct option is 'both kinetic and potential energy'.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>14","subject":"Physics","year":"2007","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)","question":"A block of mass 4.0kg causes a spiral spring to extend by 0.16m from its unstretched position. The block is removed and another body of mass 0.50 kg is hung from the same spiral spring. If the spring is then stretched and released, what is the angular frequency of the subsequent motion?   [g = 10 ms-2]","images":[],"options":{"A":"10&radic;5&nbsp; rad s-1","B":"5&radic;2&nbsp; rad s-1","C":"5 rad s-1","D":"&radic;5&nbsp; rad s-1"},"answer":"A","explanation":"* The mass of the block, m = 4.00kg = 40N  * The extension, e = 0.16m  * Recall that: F = Ke ; K=Fe=400.16=250Nm-1  Also recall: (1)F=1T(Frequencyisthereciprocaloftime)  T=2\u03c0&radic;m&nbsp;K  \u2234F=K2\u03c0&radic;m&nbsp;=2502\u03c0&radic;0.5&nbsp; = 10&radic;5&nbsp; rad s-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>15","subject":"Physics","year":"2007","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"An external force of magnitude 100 N  acts on a particle of mass 0.15kg for 0.03s. Calculate the change in the speed of the particle.","images":[],"options":{"A":"50 ms-1","B":"25 ms-1","C":"20 ms-1","D":"5 ms-1"},"answer":"C","explanation":"Given:  Force, F = 100N, mass, m = 0.15kg, Time, t = 0.03s; change in speed, \u0394v = ?  Recall:   F=m\u0394t  Ftm=\u0394V;  \u0394V=100\u00d70.030.15=30.15=20ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>16","subject":"Physics","year":"2007","type":"Objective","topic":"MOTION : CAUSE OF MOTION","question":"A car of mass 800 kg moves from rest on a horizontal track and travels 60 m in 20s with uniform acceleration. Assuming there were no frictional forces, calculate the accelerating force.","images":[],"options":{"A":"240.00 N","B":"800.00 N","C":"1600.00 N","D":"2400.00 N"},"answer":"A","explanation":"Given:  Mass, m = 800kg, Initial velocity, u = 0ms-1 (from rest); Velocity, V = 60m/20s = 3ms-1  Force, F = ?   Recall that; F=m(v - u)t=ma  Also recall, S = ut + 1/2 at2  \u2234 60 = 0(20) + 1/2 \u00d7 a \u00d7 (20)2  60=12\u00d7a\u00d7400  60 = 200a  a = 0.3ms-2  From, F = ma; F = 0.3 \u00d7 800   = 240N","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>17","subject":"Physics","year":"2007","type":"Objective","topic":"WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY","question":"A plane inclined at 30\u00b0 to the horizontal has an efficiency of 50%. Calculate the force parallel to the plane required to push a load of 120N uniformly up the plane.","images":[],"options":{"A":"50.0 N","B":"120.0 N","C":"200.0 N","D":"240.0 N"},"answer":"B","explanation":"Given: Angle, \u03b8 = 30\u00b0, Efficiency, E = 50%, Load, L = 120N; Effort, E = ?  Efficiency=Mechanical AdvantageVelocity Ratio\u00d71001  50100=120E\u00d7sin30\u00b0  12=60E  E = 120N.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>18","subject":"Physics","year":"2007","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"Mechanical energy can be either","images":[],"options":{"A":"kinetic or electric","B":"chemical or potential","C":"potential or kinetic","D":"electric or heat"},"answer":"C","explanation":"Mechanical energy is the sum of kinetic and potential energy in an object that is used to do work. Kinetic energy is the energy of motion and potential energy is the energy stored in an object due to its position or state. Therefore, the correct answer is 'potential or kinetic'.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>19","subject":"Physics","year":"2007","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The ice and steam points on a mercury-in-glass thermometer are 10 cm and 30 cm respectively. Calculate the temperature in degree celsius when the mercury meniscus is at the 14 cm mark.","images":[],"options":{"A":"20\u00b0C","B":"30\u00b0C","C":"34\u00b0C","D":"70\u00b0C"},"answer":"A","explanation":"Given:  The ice point = 10cm  The steam point = 30cm  The temperature when the meniscus is at the 14cm mark is unknown  \u2234x - 0100 - 0=14 - 1030 - 10  \u2234x 100=420  x5=4;  x = 20\u00b0C","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>20","subject":"Physics","year":"2007","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Which of the following surfaces will radiate heat energy best?","images":[],"options":{"A":"Red surface","B":"White surface","C":"Black surface","D":"Yellow surface"},"answer":"C","explanation":"Black surfaces are the best emitters of heat radiation. This is because black surfaces absorb all wavelengths of light and convert them into heat, so they are also the best at emitting heat. Therefore, the correct answer is 'Black surface'.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>21","subject":"Physics","year":"2007","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"Which of the following statements distinguishes thermal conduction from convection?  I. Conduction requires a material medium while convection does not  II. In convection, there is actual motion of hot material while in conduction, molecules vibrate faster about their mean positions.  III. Conduction takes place in solids while convection takes place in fluids.","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"I, II and III"},"answer":"B","explanation":"In convection, there is actual motion of hot material while in conduction, molecules vibrate faster about their mean positions. Conduction takes place in solids while convection takes place in fluids.  \u2234 II and III are correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>22","subject":"Physics","year":"2007","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A cube made of a metal of linear expansivity \u03b1 is heated through a temperature \u03b8. If the initial volume of the cube is Vo, the correct expression for the increase in volume of the cube is","images":[],"options":{"A":"1/3 \u03b1 Vo\u03b8","B":"1/2 \u03b1 Vo\u03b8","C":"2 \u03b1 Vo\u03b8","D":"3 \u03b1 Vo\u03b8"},"answer":"D","explanation":"Recall: Cubic expansivity = 3 \u00d7 Linear expansivity  \u2234 Cubic expansivity = 3\u03b1  Cubicexpansivity=Change in volumeOriginal volume\u00d7Change in temperature  \u22343\u03b1=Change in volumeV0 \u00d7 \u0394\u03b8  \u2234 change in volume = 3\u03b1 Vo\u0394\u03b8","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>23","subject":"Physics","year":"2007","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A relative density bottle of volume 50 cm3 is completely filled with a liquid at 30o. It is then heated to 80\u00b0C such that 0.75 cm3 of the liquid is expelled. Calculate the apparent cube expansivity of the liquid.","images":[],"options":{"A":"0.00030 k-1","B":"0.00032 k-1","C":"0.01970 k-1","D":"0.02030 k-1"},"answer":"A","explanation":"Given:  Volume of bottle = 50cm3  Initial temperature = 30\u00b0C  Final temperature = 80\u00b0C  Volume of the liquid expelled = 0.75cm2  \u03b3a=Volume expelledVolume left \u00d7 temperature rise  =0.7549.25 \u00d7 50 = 0.00030k-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>24","subject":"Physics","year":"2007","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"A body of mass 200g and specific heat capacity 0.4 Jg-1 k-1 cools from 37oC to 31oC. Calculate the quantity of heat released by the body.","images":[],"options":{"A":"4800J","B":"1200J","C":"480J","D":"202J"},"answer":"C","explanation":"Given:  Mass of the body, m = 200g  Specific Heat Capacity, SHC = 0.4jg-1k-1  Temperature rise = 37\u00b0c - 31\u00b0c = 6*degc  Quantity of heat, Q = mc\u0394\u03b8  Q = 200 \u00d7 0.4 \u00d7 6   = 480J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>25","subject":"Physics","year":"2007","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"At standard atmospheric pressure, a solution of common salt is heated gradually until most of it boils away. Which of the following diagrams correctly illustrates the temperature (\u03b8) versus time (t) graph for this process?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"A","explanation":"The graph illustrated in the answer above best describes the information given.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>26","subject":"Physics","year":"2007","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"According to the kinetic theory of gases, which of the following properties of a gas can be can be affected by the collision of the gas molecules with the walls of its container?","images":[],"options":{"A":"Temperature","B":"Energy","C":"Viscosity","D":"Pressure"},"answer":"D","explanation":"Pressure is the effective force of collision with which the molecules of a gas collide with a unit area of the wall of the container.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>27","subject":"Physics","year":"2007","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"The pressure of fixed mass of an ideal gas at 27oC is 3Pa. The gas is heated at a constant volume until its pressure is 5Pa. Determine the new temperature of the gas.","images":[],"options":{"A":"100\u00b0C","B":"227\u00b0C","C":"273\u00b0C","D":"500\u00b0C"},"answer":"B","explanation":"Given:  P1 = 3Pa; T1 = 27\u00b0c = 300k; P2 = 5Pa; T2 = ?  V1 = V2  P1T1=P2T2  \u22343300=5T2  3T2 = 1500  T2 = 500K = 227\u00b0c.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>28","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following waves is electromagnetic?","images":[],"options":{"A":"X-rays","B":"Sound waves","C":"Water waves","D":"Tidal waves"},"answer":"A","explanation":"X-rays are a type of electromagnetic wave. Electromagnetic waves are waves that can travel through the vacuum of outer space. Mechanical waves, such as sound waves and water waves, require a medium in order to travel. The electromagnetic spectrum is a continuum of all electromagnetic waves arranged according to frequency and wavelength.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>29","subject":"Physics","year":"2007","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The distance between two points P and Q, along a wave is 0.05m. If the wavelength of the wave is 0.10m. Determine the angle between P and Q in radians.","images":[],"options":{"A":"0.1\u03c0","B":"\u03c0","C":"2\u03c0","D":"10\u03c0"},"answer":"B","explanation":"Given: Distance, x = 0.05m  Wavelength \u03bb = 0.10m  Phase angle, \u2205 = ?  Recall:  \u2205=2\u03c0\u03bbx  \u2205=2\u03c00.10\u00d70.05   \u2205=0.05\u00d72\u03c00.10   \u2205=510\u00d72\u03c0   \u2205 = \u03c0","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>30","subject":"Physics","year":"2007","type":"Objective","topic":"LIGHT WAVES : RECTILINEAR PROPAGATION OF LIGHT","question":"Which of the following phenomena is not a direct consequence of rectilinear propagation of light?","images":[],"options":{"A":"Lunar and solar eclipses","B":"Images of object in a pinhole camera","C":"Diffraction of light","D":"Shadows of opaque objects"},"answer":"C","explanation":"Rectilinear propagation of light is the principle that light travels in straight lines. This principle explains phenomena such as shadows and the operation of pinhole cameras. However, diffraction, which is the bending of light around the corners of an obstacle or aperture, is not a direct consequence of rectilinear propagation. Instead, it is a result of the wave nature of light.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>31","subject":"Physics","year":"2007","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"An objects is placed 10cm in front of a plane mirror. If it is moved 8cm farther away from the mirror, determine the distance of the final image from the mirror.","images":[],"options":{"A":"2 cm","B":"9 cm","C":"16 cm","D":"18 cm"},"answer":"D","explanation":"In a plane mirror, the magnification is unity, i.e = 1. Since the magnification = 1, object distance, u = Image distance, V  \u2234 u = v  u1 = v1 and u2 = v2  When: u1 = 10cm; v1 = 10cm  u2 = 10cm + 8cm  Also, V2 = 10cm + 8cm   = 18cm","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>32","subject":"Physics","year":"2007","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT CURVED SURFACES","question":"In which of the following pieces of apparatus is the radius of curvature equal to twice the focal length?","images":[],"options":{"A":"Dicolt lens","B":"Diverging lens","C":"Converging lens","D":"Parabolic mirror"},"answer":"C","explanation":"In a converging lens (also known as a convex lens), the radius of curvature is indeed twice the focal length. This is because the focal length is the distance from the lens to the point where light rays parallel to the axis converge, while the radius of curvature is the distance from the lens to the center of the sphere from which the lens is cut. In a converging lens, these two distances are the same, hence the radius of curvature is twice the focal length.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>33","subject":"Physics","year":"2007","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"When an object is placed at the centre of curvature of a concave mirror, its image is formed at?","images":[],"options":{"A":"the focus","B":"infinity","C":"the centre of curvature","D":"a distance twice the radius of curvature"},"answer":"C","explanation":"When an object is placed at the centre of curvature of a concave mirror, its image is formed at the centre of curvature.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>34","subject":"Physics","year":"2007","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A rectangular glass prism of thickness d and absolute refractive index n is placed on a point object, which is viewed vertically downward from above the prism. Which of the following expressions correctly defines the apparent upward displacement of the object?","images":[],"options":{"A":"d/n","B":"dn","C":"d/n-2","D":"d(n - 1)n"},"answer":"A","explanation":"Recallthat:Refractiveindex=Real depthApparent depth  Therefore, n=dApparent depth  Apparentdepth=dn","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>35","subject":"Physics","year":"2007","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"Which of the following factors can affect the speed of sound in air?  I. The temperature of the surrounding  II. The direction of wind  III. The pitch of the sound","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"I, II and III"},"answer":"A","explanation":"The factors that affect the speed of sound in air include:  - Temperature  - Wind direction  - Relative humidity.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>36","subject":"Physics","year":"2007","type":"Objective","topic":"SOUND WAVES : RESONANCE","question":"A sounding tuning fork is brought near the open end of a pipe containing air and the loudness of the sound is observed to increase. This observation is due to","images":[],"options":{"A":"an echo","B":"resonance","C":"interference","D":"reverberation"},"answer":"B","explanation":"The increase in the loudness of the sound when a sounding tuning fork is brought near the open end of a pipe is due to resonance. Resonance is a phenomenon that occurs when the frequency of a force applied to a system matches the natural frequency of vibration of the system, resulting in a large amplitude of vibration and hence an increase in loudness. Therefore, the correct answer is 'resonance'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>37","subject":"Physics","year":"2007","type":"Objective","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"Which of the following statements about sound waves is not correct? Sound waves can be","images":[],"options":{"A":"reflected","B":"refracted","C":"diffracted","D":"polarized"},"answer":"D","explanation":"Sound waves are mechanical waves and cannot be polarized. Polarization is a property of transverse waves, such as light waves, not longitudinal waves like sound. Therefore, the statement that sound waves can be polarized is not correct.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>38","subject":"Physics","year":"2007","type":"Objective","topic":"SIMPLE HARMONIC MOTION : FORCED VIBRATION AND RESONANCE","question":"Which of the following statements is correct about resonance? Resonance occurs when a body","images":[],"options":{"A":"vibrates with its natural frequency","B":"is forced to vibrate at its own natural frequency by another body vibrating at the same frequency","C":"vibrates at the frequency of the body causing the vibration","D":"vibrates with an irregular frequency"},"answer":"B","explanation":"Resonance occurs when a body is forced to vibrate at its own natural frequency by another body vibrating at the same frequency.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>39","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"A dry plastic comb used in combing hair was found to attract pieces of paper and dust. The most probable explanation for this phenomenon is that the comb has been given.","images":[],"options":{"A":"magnetization by induction","B":"electric charges by induction","C":"electric charges by conduction","D":"electric charges by friction"},"answer":"D","explanation":"When a dry plastic comb is used to comb hair, it can become charged due to friction. This is known as triboelectric effect or charging by friction. The comb then attracts pieces of paper and dust due to electrostatic attraction.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2007>40","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTRIC FIELD : STORAGE OF CHARGES","question":"Which of the following components is used for storing electric charges?","images":[],"options":{"A":"Inductor","B":"Resistor","C":"Capacitor","D":"Electrometer"},"answer":"C","explanation":"A capacitor is used for storing electric charges. It is a passive electronic component with two terminals. The effect of a capacitor is known as capacitance. While some capacitance exists between any two electrical conductors in proximity in a circuit, a capacitor is a component designed to add capacitance to a circuit.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>41","subject":"Physics","year":"2007","type":"Objective","topic":"DESCRIPTION PROPERTY OF FIELDS : PROPERTIES OF A FORCE FIELD","question":"Which of the following operations does not represent an action of a force field?","images":[],"options":{"A":"Falling of a mango fruit from the tree","B":"Picking of nails using a bar magnet","C":"Repulsion of two like charges","D":"Pushing of a wheel-barrow on a level ground"},"answer":"D","explanation":"Falling of a mango fruit from the tree represent the action of gravitational force field.  Picking of nails using a bar magnet & Repulsion of two like charges represent the action of the magnetic force field.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>42","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Calculate the effective resistance between P and Q in the diagram shown above.","images":["data:image/png;base64,"],"options":{"A":"0.75\u03a9","B":"4.00\u03a9","C":"5.00\u03a9","D":"7.00\u03a9"},"answer":"B","explanation":"Given: The diagram  The 2 \u03a9 resistors are parallel to one another. Therefore,theireffectiveresistance=2\u00d722+2=44=1\u03a9    Then the diagram becomes:    Now, the 3\u03a9 resistors is in series with the 1\u03a9 resistor. Therefore, the effective resistance = 3 + 1 = 4\u03a9    N.B:  (1) If resistors are in parallel, the effective resistance is equal to the reciprocal of the sum of the reciprocals of the resistance.  (2) If resistors are in serial arrangement, the effective resistance is equal to the sum of the resistance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>43","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"A bulb marked 240V, 40W is used for 30 minutes. Calculate the heat generated","images":[],"options":{"A":"320J","B":"400J","C":"10800J","D":"72000J"},"answer":"D","explanation":"Given:  Voltage, V = 240v  Power, P = 40W  Time, T = 30minutes = 1800seconds (60 seconds = 1 minute)  Heat energy generated = ?  Recall that: Electrical energy = Power \u00d7 Time  It should be noted that in this case, Electrical energy = Heat energy   \u2234 Heat energy = Power \u00d7 Time = 40 \u00d7 1800   = 72000J","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>44","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"Five 80 - W and three 100 - W lamps are run for 8 hours. If the cost of energy is N5.00 per unit, calculate the cost of running the lamps.","images":[],"options":{"A":"N280.00","B":"N28.00","C":"N7.20","D":"N1.44"},"answer":"B","explanation":"For five 80W  = 80 x 5 = 400  Three 100W = 100 x 3  Total power = 700  for 8 hours = 700 x 8  = 5600  ConvertingtoKW=5600100  = 5.6KW  Amount = 5 x 5.6,   = 28.00","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>45","subject":"Physics","year":"2007","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following electromagnetic wave can be detected by its heating effect?","images":[],"options":{"A":"Ultraviolet radiation","B":"X-rays","C":"Gamma rays","D":"Infrared radiation"},"answer":"D","explanation":"Infrared radiation is known for its heating effect. It is the type of electromagnetic radiation that is most associated with heat, as it is emitted by hot objects and can be absorbed by objects, causing them to heat up. This is why it is used in heat lamps and thermal imaging cameras.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>46","subject":"Physics","year":"2007","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"If a gas is excited by high voltage to produce a discharge, and the light is examined in a spectrometer","images":[],"options":{"A":"an explosion is observed","B":"the rainbow colours are seen","C":"an emission spectrum is observed","D":"dark lines are observed"},"answer":"C","explanation":"When a gas is excited by high voltage, it emits light at specific wavelengths, which correspond to the energy differences between the energy levels of the atoms in the gas. When this light is examined in a spectrometer, an emission spectrum is observed. This spectrum consists of bright lines at the wavelengths of the emitted light, against a dark background. This is different from an absorption spectrum, where dark lines are seen against a continuous spectrum, which would be observed if white light were passed through a cool gas.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>47","subject":"Physics","year":"2007","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The number of protons in an element increased by one after a radioactive decay. The element must have decayed by emitting","images":[],"options":{"A":"a beta particle","B":"an alpha particle","C":"a gamma ray","D":"a neutron"},"answer":"A","explanation":"The number of proton increased by one. Since atomic number = number of proton,   We can then say that the atomic number increased by 1.  abX \u2192 ab + 1P + o-1e   \u2234 The atom has been decayed by Beta particle emitting a beta particle.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>48","subject":"Physics","year":"2007","type":"Objective","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"The correct sequence of energy transformations in the operation of an X-ray tube is   I. X-rays   II. Kinetic energy of thermo electrons   III. Potential energy of the target atoms  IV. Heat energy of the emitted electrons","images":[],"options":{"A":"IV, III, II, I","B":"IV, II, III, I","C":"II, IV, III, I","D":"III, IV, II, I"},"answer":"B","explanation":"In the operation of X-ray tube, energy is transmitted in this order.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2007>49","subject":"Physics","year":"2007","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"In a nuclear reactor, chain reactions result from the release of","images":[],"options":{"A":"electrons","B":"photons","C":"neutrons","D":"protons"},"answer":"C","explanation":"In a nuclear reactor, chain reactions result from the release of neutrons. When a neutron strikes the nucleus of a fissile atom, the nucleus splits, releasing energy and additional neutrons. These newly released neutrons can then cause further fissions, leading to a chain reaction.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2007>50","subject":"Physics","year":"2007","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"There is always an uncertainty involved in any attempt to measure the position and momentum of an electron simultaneously. This statement is known as the","images":[],"options":{"A":"De Broglie's law","B":"Heisenberg uncertainty principle","C":"Franck-Hertz experimental law","D":"Wave-particle paradox"},"answer":"B","explanation":"The statement is known as the Heisenberg uncertainty principle. This principle states that it is impossible to simultaneously measure the exact position and momentum of a particle. In other words, the more precisely one property is measured, the less precisely the other can be controlled, determined, or known.","marks":"1","difficulty":"3"}];